CREATE OR REPLACE FUNCTION calc_vertex_figures_angle_gap_deg(p_vertex_figure_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (ABS((COALESCE(CASE WHEN ((SELECT angle_sum_deg FROM vertex_figures WHERE vertex_figure_id = p_vertex_figure_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT angle_sum_deg FROM vertex_figures WHERE vertex_figure_id = p_vertex_figure_id))::numeric ELSE NULL END, 0) - COALESCE(360, 0))))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_vertex_figures_is_valid
-- Field: VertexFigures.IsValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_vertex_figures_is_valid(p_vertex_figure_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_vertex_figures_angle_gap_deg(p_vertex_figure_id))::NUMERIC <= 0.0001)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_regions_name
-- Field: Regions.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_regions_name(p_region_id TEXT)
RETURNS TEXT AS $$
  SELECT (REPLACE(LOWER((SELECT NULLIF(display_name, '') FROM regions WHERE region_id = p_region_id)), ' ', '-'))::text;
$$ LANGUAGE sql STABLE;

-- calc_regions_area
-- Field: Regions.Area
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_regions_area(p_region_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT width FROM regions WHERE region_id = p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT width FROM regions WHERE region_id = p_region_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT height FROM regions WHERE region_id = p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT height FROM regions WHERE region_id = p_region_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_regions_placement_count
-- Field: Regions.PlacementCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_regions_placement_count(p_region_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM placements WHERE region = (SELECT NULLIF(region_id, '') FROM regions WHERE region_id = p_region_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_regions_covered_area
-- Field: Regions.CoveredArea
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_regions_covered_area(p_region_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_placements_tile_area(placement_id))::numeric), 0) FROM placements WHERE region = p_region_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_regions_overlap_count
-- Field: Regions.OverlapCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_regions_overlap_count(p_region_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM placements WHERE region = (SELECT NULLIF(region_id, '') FROM regions WHERE region_id = p_region_id) AND is_overlapping = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_regions_coverage_pct
-- Field: Regions.CoveragePct
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_regions_coverage_pct(p_region_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(100, 0) * COALESCE(CASE WHEN ((COALESCE(CASE WHEN (calc_regions_covered_area(p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_regions_covered_area(p_region_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_regions_area(p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_regions_area(p_region_id))::numeric ELSE NULL END, 0), 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (calc_regions_covered_area(p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_regions_covered_area(p_region_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_regions_area(p_region_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_regions_area(p_region_id))::numeric ELSE NULL END, 0), 0)))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_regions_is_fully_covered
-- Field: Regions.IsFullyCovered
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_regions_is_fully_covered(p_region_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_regions_coverage_pct(p_region_id))::NUMERIC >= 100)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_regions_is_clean_tiling
-- Field: Regions.IsCleanTiling
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_regions_is_clean_tiling(p_region_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_regions_is_fully_covered(p_region_id) AND (calc_regions_overlap_count(p_region_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_placements_tile_area
-- Field: Placements.TileArea
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: Area from related Prototiles


CREATE OR REPLACE FUNCTION calc_placements_tile_area(p_placement_id TEXT)
RETURNS NUMERIC AS $$
  SELECT calc_prototiles_area((SELECT prototile FROM placements WHERE placement_id = p_placement_id));
$$ LANGUAGE sql STABLE;

-- calc_placements_tile_sides
